1	package httpx
2	
3	import (
4		"net/http"
5	
6		"github.com/labstack/echo/v4"
7	)
8	
9	// APIError is the normalized error response envelope returned by every
10	// endpoint. It matches the project's error contract exactly.
11	type APIError struct {
12		Error ErrorBody `json:"error"`
13	}
14	
15	// ErrorBody holds the details inside the "error" key.
16	type ErrorBody struct {
17		Code        string              `json:"code"`
18		Message     string              `json:"message"`
19		FieldErrors map[string][]string `json:"field_errors,omitempty"`
20		RequestID   string              `json:"request_id,omitempty"`
21	}
22	
23	// NewAPIError creates an APIError with the given HTTP status code, error code,
24	// and human-readable message.
25	func NewAPIError(httpStatus int, code, message string) *echo.HTTPError {
26		return &echo.HTTPError{
27			Code: httpStatus,
28			Message: APIError{
29				Error: ErrorBody{
30					Code:    code,
31					Message: message,
32				},
33			},
34		}
35	}
36	
37	// NewValidationError creates a 422 Unprocessable Entity error with per-field
38	// validation messages.
39	func NewValidationError(fieldErrors map[string][]string) *echo.HTTPError {
40		return &echo.HTTPError{
41			Code: http.StatusUnprocessableEntity,
42			Message: APIError{
43				Error: ErrorBody{
44					Code:        "validation_error",
45					Message:     "One or more fields failed validation.",
46					FieldErrors: fieldErrors,
47				},
48			},
49		}
50	}
51	
52	// NewNotFoundError creates a 404 Not Found error.
53	func NewNotFoundError(message string) *echo.HTTPError {
54		return NewAPIError(http.StatusNotFound, "not_found", message)
55	}
56	
57	// NewForbiddenError creates a 403 Forbidden error.
58	func NewForbiddenError(message string) *echo.HTTPError {
59		return NewAPIError(http.StatusForbidden, "forbidden", message)
60	}
61	
62	// NewConflictError creates a 409 Conflict error.
63	func NewConflictError(code, message string) *echo.HTTPError {
64		return NewAPIError(http.StatusConflict, code, message)
65	}
66	
67	// ErrorHandler is a custom Echo error handler that ensures every error
68	// response conforms to the normalized error contract.
69	func ErrorHandler(err error, c echo.Context) {
70		if c.Response().Committed {
71			return
72		}
73	
74		requestID := c.Response().Header().Get(echo.HeaderXRequestID)
75	
76		he, ok := err.(*echo.HTTPError)
77		if !ok {
78			// Unexpected error - wrap it
79			he = NewAPIError(http.StatusInternalServerError, "internal_error", "An unexpected error occurred.")
80		}
81	
82		// If the message is already our APIError, inject the request ID and send.
83		if apiErr, ok := he.Message.(APIError); ok {
84			apiErr.Error.RequestID = requestID
85			_ = c.JSON(he.Code, apiErr)
86			return
87		}
88	
89		// Fallback for Echo's own errors (404 route not found, etc.)
90		msg := "An unexpected error occurred."
91		if m, ok := he.Message.(string); ok {
92			msg = m
93		}
94	
95		resp := APIError{
96			Error: ErrorBody{
97				Code:      http.StatusText(he.Code),
98				Message:   msg,
99				RequestID: requestID,
100			},
101		}
102		_ = c.JSON(he.Code, resp)
103	}
