1	package httpx
2	
3	import (
4		"encoding/json"
5		"log"
6		"time"
7	
8		"github.com/google/uuid"
9		"github.com/labstack/echo/v4"
10	)
11	
12	// RequestID returns middleware that sets a unique X-Request-Id header on every
13	// request. If the client already provides one it is preserved.
14	func RequestID() echo.MiddlewareFunc {
15		return func(next echo.HandlerFunc) echo.HandlerFunc {
16			return func(c echo.Context) error {
17				rid := c.Request().Header.Get(echo.HeaderXRequestID)
18				if rid == "" {
19					rid = uuid.New().String()
20				}
21				c.Request().Header.Set(echo.HeaderXRequestID, rid)
22				c.Response().Header().Set(echo.HeaderXRequestID, rid)
23				return next(c)
24			}
25		}
26	}
27	
28	// RequestLogger returns middleware that emits a structured JSON log line for
29	// every completed request. This is a minimal placeholder; swap in zerolog or
30	// slog for production use.
31	func RequestLogger() echo.MiddlewareFunc {
32		return func(next echo.HandlerFunc) echo.HandlerFunc {
33			return func(c echo.Context) error {
34				start := time.Now()
35	
36				err := next(c)
37				if err != nil {
38					c.Error(err)
39				}
40	
41				entry := map[string]interface{}{
42					"method":     c.Request().Method,
43					"path":       c.Request().URL.Path,
44					"status":     c.Response().Status,
45					"latency_ms": time.Since(start).Milliseconds(),
46					"request_id": c.Response().Header().Get(echo.HeaderXRequestID),
47				}
48	
49				line, _ := json.Marshal(entry)
50				log.Println(string(line))
51	
52				return nil
53			}
54		}
55	}
