server {
    listen 80;
    server_name _;
    root /usr/share/nginx/html;
    index index.html;

    # SPA fallback - serve index.html for all non-file routes
    location / {
        try_files $uri $uri/ /index.html;
    }

    # Proxy API requests to the backend service
    location /api/ {
        proxy_pass http://api:8080;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }

    # Cache static assets
    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
    }
}

1	const API_BASE = "/api/v1";
2	
3	export interface ApiFieldError {
4	  field: string;
5	  message: string;
6	}
7	
8	export interface ApiErrorBody {
9	  error: {
10	    code: string;
11	    message: string;
12	    field_errors?: ApiFieldError[];
13	    request_id?: string;
14	  };
15	}
16	
17	export class ApiError extends Error {
18	  code: string;
19	  status: number;
20	  fieldErrors: ApiFieldError[];
21	  requestId?: string;
22	
23	  constructor(status: number, body: ApiErrorBody) {
24	    super(body.error.message);
25	    this.name = "ApiError";
26	    this.status = status;
27	    this.code = body.error.code;
28	    this.fieldErrors = body.error.field_errors ?? [];
29	    this.requestId = body.error.request_id;
30	  }
31	}
32	
33	async function request<T>(
34	  path: string,
35	  options: RequestInit = {},
36	): Promise<T> {
37	  const res = await fetch(`${API_BASE}${path}`, {
38	    credentials: "include",
39	    headers: {
40	      "Content-Type": "application/json",
41	      ...options.headers,
42	    },
43	    ...options,
44	  });
45	
46	  if (!res.ok) {
47	    let body: ApiErrorBody;
48	    try {
49	      body = await res.json();
50	    } catch {
51	      throw new ApiError(res.status, {
52	        error: {
53	          code: "UNKNOWN",
54	          message: res.statusText,
55	        },
56	      });
57	    }
58	    throw new ApiError(res.status, body);
59	  }
60	
61	  if (res.status === 204) {
62	    return undefined as T;
63	  }
64	
65	  return res.json();
66	}
67	
68	export const api = {
69	  get: <T>(path: string) => request<T>(path),
70	
71	  post: <T>(path: string, body?: unknown) =>
72	    request<T>(path, {
73	      method: "POST",
74	      body: body ? JSON.stringify(body) : undefined,
75	    }),
76	
77	  put: <T>(path: string, body?: unknown) =>
78	    request<T>(path, {
79	      method: "PUT",
80	      body: body ? JSON.stringify(body) : undefined,
81	    }),
82	
83	  patch: <T>(path: string, body?: unknown) =>
84	    request<T>(path, {
85	      method: "PATCH",
86	      body: body ? JSON.stringify(body) : undefined,
87	    }),
88	
89	  delete: <T>(path: string) =>
90	    request<T>(path, { method: "DELETE" }),
91	};
