97	// HandleBootstrapAdmin handles POST /auth/bootstrap-admin.
98	func (s *Service) HandleBootstrapAdmin(c echo.Context) error {
99		var req bootstrapRequest
100		if err := c.Bind(&req); err != nil {
101			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
102		}
103	
104		fieldErrors := map[string][]string{}
105		if req.Username == "" {
106			fieldErrors["username"] = []string{"Username is required."}
107		}
108		if req.Password == "" {
109			fieldErrors["password"] = []string{"Password is required."}
110		} else if len(req.Password) < 8 {
111			fieldErrors["password"] = []string{"Password must be at least 8 characters."}
112		}
113		if req.Email == "" {
114			fieldErrors["email"] = []string{"Email is required."}
115		}
116		if len(fieldErrors) > 0 {
117			return httpx.NewValidationError(fieldErrors)
118		}
