125		s.audit.Log(c.Request().Context(), audit.Event{
126			EventType:    "bootstrap_admin",
127			ActorID:      user.ID,
128			ResourceType: "auth",
129		})
130	
131		return c.JSON(http.StatusCreated, userResponse{User: user})
132	}
