2	
3	import (
4		"net/http"
5	
6		"fieldserve/internal/audit"
7		"fieldserve/internal/platform/httpx"
8	
9		"github.com/labstack/echo/v4"
10	)
11	
12	// RequireAuth returns middleware that validates the session cookie and sets
13	// the authenticated user in the echo context.
14	func (s *Service) RequireAuth() echo.MiddlewareFunc {
15		return func(next echo.HandlerFunc) echo.HandlerFunc {
16			return func(c echo.Context) error {
17				token := s.GetSessionToken(c)
18				if token == "" {
19					return httpx.NewAPIError(http.StatusUnauthorized, "unauthenticated", "Authentication required.")
20				}
21	
22				user, err := s.ResolveSession(c.Request().Context(), token)
23				if err != nil {
24					return err
25				}
26				if user == nil {
27					s.ClearSessionCookie(c)
28					return httpx.NewAPIError(http.StatusUnauthorized, "unauthenticated", "Authentication required.")
29				}
30	
31				c.Set("auth_user", user)
32				return next(c)
33			}
34		}
35	}
36	
37	// RequireRole returns middleware that checks if the authenticated user has at
38	// least one of the required roles. RequireAuth must run before this middleware.
39	func RequireRole(auditSvc *audit.Service, roles ...string) echo.MiddlewareFunc {
40		return func(next echo.HandlerFunc) echo.HandlerFunc {
41			return func(c echo.Context) error {
42				user := UserFromContext(c)
43				if user == nil {
44					return httpx.NewAPIError(http.StatusUnauthorized, "unauthenticated", "Authentication required.")
45				}
46	
47				for _, required := range roles {
48					for _, userRole := range user.Roles {
49						if userRole == required {
50							return next(c)
51						}
52					}
53				}
54	
55				// User does not have any of the required roles
56				auditSvc.Log(c.Request().Context(), audit.Event{
57					EventType:    "privilege_escalation",
58					ActorID:      user.ID,
59					ResourceType: "auth",
60					Metadata: map[string]interface{}{
61						"route":          c.Request().Method + " " + c.Request().URL.Path,
62						"required_roles": roles,
63					},
64				})
65	
66				return httpx.NewAPIError(http.StatusForbidden, "forbidden", "Insufficient permissions.")
67			}
68		}
69	}
