1	import { create } from "zustand";
2	import { api, ApiError } from "../api/client";
3	
4	export interface AuthUser {
5	  id: string;
6	  username: string;
7	  email: string;
8	  roles: string[];
9	}
10	
11	interface AuthState {
12	  user: AuthUser | null;
13	  loading: boolean;
14	  error: string | null;
15	
16	  bootstrap: () => Promise<void>;
17	  login: (username: string, password: string) => Promise<AuthUser>;
18	  logout: () => Promise<void>;
19	}
20	
21	export const useAuthStore = create<AuthState>()((set) => ({
22	  user: null,
23	  loading: true,
24	  error: null,
25	
26	  bootstrap: async () => {
27	    try {
28	      const data = await api.get<{ user: AuthUser }>("/auth/me");
29	      set({ user: data.user, loading: false, error: null });
30	    } catch (err) {
31	      set({ user: null, loading: false, error: null });
32	    }
33	  },
34	
35	  login: async (username: string, password: string) => {
36	    const data = await api.post<{ user: AuthUser }>("/auth/login", {
37	      username,
38	      password,
39	    });
40	    set({ user: data.user, error: null });
41	    return data.user;
42	  },
43	
44	  logout: async () => {
45	    try {
46	      await api.post("/auth/logout");
47	    } finally {
48	      set({ user: null });
49	    }
50	  },
51	}));
52	
53	export function hasRole(user: AuthUser | null, role: string): boolean {
54	  return user?.roles.includes(role) ?? false;
55	}
56	
57	export function primaryRole(user: AuthUser | null): string | null {
58	  if (!user) return null;
59	  if (user.roles.includes("administrator")) return "administrator";
60	  if (user.roles.includes("provider")) return "provider";
61	  if (user.roles.includes("customer")) return "customer";
62	  return null;
63	}
64	
65	export function roleHomePath(role: string | null): string {
66	  switch (role) {
67	    case "administrator":
68	      return "/admin";
69	    case "provider":
70	      return "/provider";
71	    case "customer":
72	      return "/customer";
73	    default:
74	      return "/login";
75	  }
76	}
