68	        }
69	      >
70	        <Route index element={<AdminDashboardPage />} />
71	      </Route>
72	
73	      <Route path="/" element={<RootRedirect />} />
74	      <Route path="*" element={<NotFoundPage />} />
75	    </Routes>
