15	
16	  if (user) {
17	    return <Navigate to={roleHomePath(primaryRole(user))} replace />;
18	  }
19	
20	  const handleSubmit = async (e: FormEvent) => {
21	    e.preventDefault();
22	    setError(null);
23	    setSubmitting(true);
24	
25	    try {
26	      const loggedInUser = await login(username, password);
27	      navigate(roleHomePath(primaryRole(loggedInUser)));
28	    } catch (err) {
29	      if (err instanceof ApiError) {
30	        setError(err.message);
31	      } else {
32	        setError("An unexpected error occurred.");
33	      }
34	    } finally {
35	      setSubmitting(false);
36	    }
37	  };
38	
39	  return (
40	    <div className="flex min-h-screen items-center justify-center bg-gray-50">
41	      <div className="w-full max-w-sm rounded-lg bg-white p-8 shadow">
42	        <h1 className="mb-6 text-center text-2xl font-bold text-gray-900">
43	          FieldServe
44	        </h1>
45	        <form onSubmit={handleSubmit} className="space-y-4">
46	          <div>
47	            <label
48	              htmlFor="username"
49	              className="block text-sm font-medium text-gray-700"
50	            >
51	              Username
52	            </label>
53	            <input
54	              id="username"
55	              type="text"
56	              value={username}
57	              onChange={(e) => setUsername(e.target.value)}
58	              className="mt-1 block w-full rounded border border-gray-300 px-3 py-2 shadow-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
59	              required
60	            />
61	          </div>
62	          <div>
63	            <label
64	              htmlFor="password"
65	              className="block text-sm font-medium text-gray-700"
66	            >
67	              Password
68	            </label>
69	            <input
70	              id="password"
71	              type="password"
72	              value={password}
73	              onChange={(e) => setPassword(e.target.value)}
74	              className="mt-1 block w-full rounded border border-gray-300 px-3 py-2 shadow-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
75	              required
76	            />
77	          </div>
78	          {error && (
79	            <div className="rounded bg-red-50 p-3 text-sm text-red-600">
80	              {error}
81	            </div>
82	          )}
83	          <button
84	            type="submit"
85	            disabled={submitting}
86	            className="w-full rounded bg-blue-600 px-4 py-2 text-white hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 disabled:opacity-50"
87	          >
88	            {submitting ? "Signing in..." : "Sign In"}
89	          </button>
90	        </form>
91	      </div>
92	    </div>
