import { api } from "./client";

export interface Category {
  id: string;
  parent_id: string | null;
  name: string;
  slug: string;
  sort_order: number;
  created_at: string;
}

export interface Tag {
  id: string;
  name: string;
  created_at: string;
}

export interface ServiceSummary {
  id: string;
  title: string;
  description: string | null;
  price_cents: number;
  rating_avg: string;
  popularity_score: number;
  status: string;
  category: { id: string; name: string } | null;
  provider: { id: string; business_name: string };
  tags: { id: string; name: string }[];
  created_at: string;
  updated_at: string;
}

export interface ServiceDetail extends ServiceSummary {
  availability: {
    id: string;
    day_of_week: number;
    start_time: string;
    end_time: string;
  }[];
}

// Catalog reads
export const catalogApi = {
  listCategories: () =>
    api.get<{ categories: Category[] }>("/catalog/categories"),
  listTags: () => api.get<{ tags: Tag[] }>("/catalog/tags"),
  listServices: (params?: {
    page?: number;
    page_size?: number;
    category_id?: string;
  }) => {
    const qs = new URLSearchParams();
    if (params?.page) qs.set("page", String(params.page));
    if (params?.page_size) qs.set("page_size", String(params.page_size));
    if (params?.category_id) qs.set("category_id", params.category_id);
    const q = qs.toString();
    return api.get<{
      services: ServiceSummary[];
      total: number;
      page: number;
      page_size: number;
    }>(`/catalog/services${q ? "?" + q : ""}`);
  },
  getService: (id: string) =>
    api.get<{ service: ServiceDetail }>(`/catalog/services/${id}`),
};

// Admin taxonomy
export const adminApi = {
  listCategories: () =>
    api.get<{ categories: Category[] }>("/admin/categories"),
  createCategory: (data: {
    name: string;
    slug: string;
    parent_id?: string | null;
    sort_order?: number;
  }) => api.post<{ category: Category }>("/admin/categories", data),
  updateCategory: (
    id: string,
    data: Partial<{
      name: string;
      slug: string;
      parent_id: string | null;
      sort_order: number;
    }>,
  ) => api.patch<{ category: Category }>(`/admin/categories/${id}`, data),
  listTags: () => api.get<{ tags: Tag[] }>("/admin/tags"),
  createTag: (data: { name: string }) =>
    api.post<{ tag: Tag }>("/admin/tags", data),
  updateTag: (id: string, data: { name: string }) =>
    api.patch<{ tag: Tag }>(`/admin/tags/${id}`, data),
};

// Provider services
export const providerApi = {
  listServices: () =>
    api.get<{ services: ServiceSummary[] }>("/provider/services"),
  getService: (id: string) =>
    api.get<{ service: ServiceDetail }>(`/provider/services/${id}`),
  createService: (data: {
    category_id: string;
    title: string;
    description?: string;
    price_cents: number;
    tag_ids?: string[];
    status?: string;
  }) => api.post<{ service: ServiceSummary }>("/provider/services", data),
  updateService: (
    id: string,
    data: Partial<{
      category_id: string;
      title: string;
      description: string;
      price_cents: number;
      tag_ids: string[];
      status: string;
    }>,
  ) => api.patch<{ service: ServiceSummary }>(`/provider/services/${id}`, data),
  deleteService: (id: string) =>
    api.delete<{ message: string }>(`/provider/services/${id}`),
  setAvailability: (
    id: string,
    windows: { day_of_week: number; start_time: string; end_time: string }[],
  ) =>
    api.post<{
      availability: {
        id: string;
        day_of_week: number;
        start_time: string;
        end_time: string;
      }[];
    }>(`/provider/services/${id}/availability`, { windows }),
};
```

