1	import { useState, useEffect, useCallback } from "react";
2	import { Link } from "react-router-dom";
3	import { useQuery } from "@tanstack/react-query";
4	import { catalogApi, customerApi } from "../../api/catalog";
5	import type { ServiceSummary } from "../../api/catalog";
6	import { useCompareStore } from "../../stores/compare";
7	
8	const DAY_NAMES = [
9	  "Sunday",
10	  "Monday",
11	  "Tuesday",
12	  "Wednesday",
13	  "Thursday",
14	  "Friday",
15	  "Saturday",
16	];
17	
18	const SORT_OPTIONS = [
19	  { value: "relevance", label: "Relevance" },
20	  { value: "newest", label: "Newest" },
21	  { value: "price_asc", label: "Price (Low)" },
22	  { value: "price_desc", label: "Price (High)" },
23	  { value: "popularity", label: "Most Popular" },
24	  { value: "rating", label: "Highest Rated" },
25	];
26	
27	function formatPrice(cents: number): string {
28	  return `$${(cents / 100).toFixed(2)}`;
29	}
30	
31	function CatalogPage() {
32	  const pageSize = 20;
33	
34	  // Search & filter state
35	  const [searchInput, setSearchInput] = useState("");
36	  const [debouncedQ, setDebouncedQ] = useState("");
37	  const [categoryId, setCategoryId] = useState("");
38	  const [selectedTagIds, setSelectedTagIds] = useState<string[]>([]);
39	  const [minPrice, setMinPrice] = useState("");
40	  const [maxPrice, setMaxPrice] = useState("");
41	  const [minRating, setMinRating] = useState("");
42	  const [radiusMiles, setRadiusMiles] = useState("");
43	  const [availableFrom, setAvailableFrom] = useState("");
44	  const [sort, setSort] = useState("newest");
45	  const [page, setPage] = useState(1);
46	  const [showFilters, setShowFilters] = useState(false);
47	
48	  // Favorites state
49	  const [favoriteIds, setFavoriteIds] = useState<Set<string>>(new Set());
50	
51	  // Compare store
52	  const compareAdd = useCompareStore((s) => s.add);
53	  const compareRemove = useCompareStore((s) => s.remove);
54	  const compareHas = useCompareStore((s) => s.has);
55	  useCompareStore((s) => s.items); // subscribe for re-render on compare changes
56	
57	  // Debounce search input
58	  useEffect(() => {
59	    const timer = setTimeout(() => {
60	      setDebouncedQ(searchInput);
61	      setPage(1);
62	    }, 300);
63	    return () => clearTimeout(timer);
64	  }, [searchInput]);
65	
66	  // Load categories & tags for filters
67	  const { data: categoriesData } = useQuery({
68	    queryKey: ["catalog-categories"],
69	    queryFn: catalogApi.listCategories,
70	  });
71	  const { data: tagsData } = useQuery({
72	    queryKey: ["catalog-tags"],
73	    queryFn: catalogApi.listTags,
74	  });
75	
76	  // Load favorites
77	  const { data: favoritesData } = useQuery({
78	    queryKey: ["customer-favorites"],
79	    queryFn: customerApi.getFavorites,
80	  });
81	
82	  useEffect(() => {
83	    if (favoritesData?.favorites) {
84	      setFavoriteIds(new Set(favoritesData.favorites.map((f) => f.service_id)));
85	    }
86	  }, [favoritesData]);
87	
88	  // Search history
89	  const { data: historyData } = useQuery({
90	    queryKey: ["customer-search-history"],
91	    queryFn: customerApi.getSearchHistory,
92	  });
93	
94	  // Hot keywords
95	  const { data: hotKeywordsData } = useQuery({
96	    queryKey: ["catalog-hot-keywords"],
97	    queryFn: catalogApi.getHotKeywords,
98	  });
99	
100	  // Trending (shown when no search query)
101	  const { data: trendingData } = useQuery({
102	    queryKey: ["catalog-trending"],
103	    queryFn: catalogApi.getTrending,
104	    enabled: !debouncedQ,
105	  });
106	
107	  // Main search query
108	  const { data, isLoading, error } = useQuery({
109	    queryKey: [
110	      "catalog-services",
111	      debouncedQ,
112	      categoryId,
113	      selectedTagIds,
114	      minPrice,
115	      maxPrice,
116	      minRating,
117	      radiusMiles,
118	      availableFrom,
119	      sort,
120	      page,
121	    ],
122	    queryFn: () =>
123	      catalogApi.listServices({
124	        q: debouncedQ || undefined,
125	        category_id: categoryId || undefined,
126	        tag_ids: selectedTagIds.length ? selectedTagIds : undefined,
127	        min_price: minPrice ? Math.round(parseFloat(minPrice) * 100) : undefined,
128	        max_price: maxPrice ? Math.round(parseFloat(maxPrice) * 100) : undefined,
129	        min_rating: minRating ? parseFloat(minRating) : undefined,
130	        radius_miles: radiusMiles ? parseInt(radiusMiles, 10) : undefined,
131	        available_from: availableFrom !== "" ? parseInt(availableFrom, 10) : undefined,
132	        sort,
133	        page,
134	        page_size: pageSize,
135	      }),
136	  });
137	
138	  const categories = categoriesData?.categories ?? [];
139	  const tags = tagsData?.tags ?? [];
140	  const services = data?.services ?? [];
141	  const total = data?.total ?? 0;
142	  const totalPages = Math.ceil(total / pageSize);
143	  const history = historyData?.history ?? [];
144	  const hotKeywords = hotKeywordsData?.keywords ?? [];
145	  const trending = trendingData?.services ?? [];
146	
147	  // Favorite toggle
148	  const toggleFavorite = useCallback(
149	    async (serviceId: string) => {
150	      const isFav = favoriteIds.has(serviceId);
151	      // Optimistic update
152	      setFavoriteIds((prev) => {
153	        const next = new Set(prev);
154	        if (isFav) {
155	          next.delete(serviceId);
156	        } else {
157	          next.add(serviceId);
158	        }
159	        return next;
160	      });
161	      try {
162	        if (isFav) {
163	          await customerApi.removeFavorite(serviceId);
164	        } else {
165	          await customerApi.addFavorite(serviceId);
166	        }
167	      } catch {
168	        // Rollback
169	        setFavoriteIds((prev) => {
170	          const next = new Set(prev);
171	          if (isFav) {
172	            next.add(serviceId);
173	          } else {
174	            next.delete(serviceId);
175	          }
176	          return next;
177	        });
178	      }
179	    },
180	    [favoriteIds],
181	  );
182	
183	  // Compare toggle
184	  const toggleCompare = useCallback(
185	    (svc: ServiceSummary) => {
186	      if (compareHas(svc.id)) {
187	        compareRemove(svc.id);
188	      } else {
189	        compareAdd(svc);
190	      }
191	    },
192	    [compareAdd, compareRemove, compareHas],
193	  );
194	
195	  // Tag toggle
196	  const toggleTag = (tagId: string) => {
197	    setSelectedTagIds((prev) =>
198	      prev.includes(tagId)
199	        ? prev.filter((id) => id !== tagId)
200	        : [...prev, tagId],
201	    );
202	    setPage(1);
203	  };
204	
205	  const clearFilters = () => {
206	    setCategoryId("");
207	    setSelectedTagIds([]);
208	    setMinPrice("");
209	    setMaxPrice("");
210	    setMinRating("");
211	    setRadiusMiles("");
212	    setAvailableFrom("");
213	    setSort("newest");
214	    setPage(1);
215	  };
216	
217	  function renderServiceCard(svc: ServiceSummary) {
218	    const isFav = favoriteIds.has(svc.id);
219	    const inCompare = compareHas(svc.id);
220	
221	    return (
222	      <div
223	        key={svc.id}
224	        className="flex flex-col rounded-lg bg-white p-5 shadow-sm transition hover:shadow-md"
225	      >
226	        <Link to={`/customer/catalog/${svc.id}`} className="flex-1">
227	          <h3 className="mb-1 text-base font-semibold text-gray-900">
228	            {svc.title}
229	          </h3>
230	          <p className="mb-1 text-sm text-gray-500">
231	            {svc.provider.business_name}
232	          </p>
233	          <p className="mb-1 text-sm text-gray-500">
234	            {svc.category?.name ?? "Uncategorized"}
235	          </p>
236	          <p className="mb-2 text-lg font-bold text-gray-900">
237	            {formatPrice(svc.price_cents)}
238	          </p>
239	          <div className="mb-2 flex items-center gap-1 text-sm text-yellow-600">
240	            Rating: {svc.rating_avg}
241	          </div>
242	          {svc.tags.length > 0 && (
243	            <div className="flex flex-wrap gap-1">
244	              {svc.tags.map((tag) => (
245	                <span
246	                  key={tag.id}
247	                  className="inline-block rounded bg-blue-50 px-2 py-0.5 text-xs text-blue-700"
248	                >
249	                  {tag.name}
250	                </span>
251	              ))}
252	            </div>
253	          )}
254	        </Link>
255	        <div className="mt-3 flex items-center gap-2 border-t border-gray-100 pt-3">
256	          <button
257	            onClick={() => toggleFavorite(svc.id)}
258	            className={`rounded-md px-3 py-1.5 text-xs font-medium ${
259	              isFav
260	                ? "bg-red-50 text-red-600 hover:bg-red-100"
261	                : "bg-gray-50 text-gray-600 hover:bg-gray-100"
262	            }`}
263	          >
264	            {isFav ? "Favorited" : "Favorite"}
265	          </button>
266	          <button
267	            onClick={() => toggleCompare(svc)}
268	            className={`rounded-md px-3 py-1.5 text-xs font-medium ${
269	              inCompare
270	                ? "bg-blue-50 text-blue-600 hover:bg-blue-100"
271	                : "bg-gray-50 text-gray-600 hover:bg-gray-100"
272	            }`}
273	          >
274	            {inCompare ? "In Compare" : "+ Compare"}
275	          </button>
276	        </div>
277	      </div>
278	    );
279	  }
280	
281	  return (
282	    <div>
283	      <div className="mb-6">
284	        <h1 className="mb-4 text-2xl font-bold text-gray-900">
285	          Browse Services
286	        </h1>
287	
288	        {/* Search input */}
289	        <div className="mb-4">
290	          <input
291	            type="text"
292	            placeholder="Search services..."
293	            value={searchInput}
294	            onChange={(e) => setSearchInput(e.target.value)}
295	            className="w-full rounded-md border border-gray-300 px-4 py-2.5 text-sm shadow-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
296	          />
297	        </div>
298	
299	        {/* Hot keywords */}
300	        {hotKeywords.length > 0 && (
301	          <div className="mb-4 flex flex-wrap gap-2">
302	            {hotKeywords.map((kw) => (
303	              <button
304	                key={kw.id}
305	                onClick={() => setSearchInput(kw.keyword)}
306	                className="rounded-full bg-blue-50 px-3 py-1 text-xs font-medium text-blue-700 hover:bg-blue-100"
307	              >
308	                {kw.keyword}
309	              </button>
310	            ))}
311	          </div>
312	        )}
313	
314	        {/* Search history */}
315	        {history.length > 0 && (
316	          <div className="mb-4">
317	            <p className="mb-1 text-xs font-medium uppercase text-gray-400">
318	              Recent Searches
319	            </p>
320	            <div className="flex flex-wrap gap-2">
321	              {history.slice(0, 10).map((h) => (
322	                <button
323	                  key={h.id}
324	                  onClick={() => setSearchInput(h.query_text)}
325	                  className="rounded-full bg-gray-100 px-3 py-1 text-xs text-gray-600 hover:bg-gray-200"
326	                >
327	                  {h.query_text}
328	                </button>
329	              ))}
330	            </div>
331	          </div>
332	        )}
333	
334	        {/* Filter toggle & sort */}
335	        <div className="mb-4 flex flex-wrap items-center justify-between gap-3">
336	          <button
337	            onClick={() => setShowFilters(!showFilters)}
338	            className="rounded-md bg-gray-100 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-200"
339	          >
340	            {showFilters ? "Hide Filters" : "Show Filters"}
341	          </button>
342	          <div className="flex items-center gap-2">
343	            <label htmlFor="sort-select" className="text-sm text-gray-600">
344	              Sort:
345	            </label>
346	            <select
347	              id="sort-select"
348	              value={sort}
349	              onChange={(e) => {
350	                setSort(e.target.value);
351	                setPage(1);
352	              }}
353	              className="rounded-md border border-gray-300 px-3 py-1.5 text-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
354	            >
355	              {SORT_OPTIONS.filter(
356	                (opt) => opt.value !== "relevance" || debouncedQ,
357	              ).map((opt) => (
358	                <option key={opt.value} value={opt.value}>
359	                  {opt.label}
360	                </option>
361	              ))}
362	            </select>
363	          </div>
364	        </div>
365	
366	        {/* Filters panel */}
367	        {showFilters && (
368	          <div className="mb-6 rounded-lg bg-white p-5 shadow-sm">
369	            <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
370	              {/* Category */}
371	              <div>
372	                <label
373	                  htmlFor="filter-category"
374	                  className="block text-sm font-medium text-gray-700"
375	                >
376	                  Category
377	                </label>
378	                <select
379	                  id="filter-category"
380	                  value={categoryId}
381	                  onChange={(e) => {
382	                    setCategoryId(e.target.value);
383	                    setPage(1);
384	                  }}
385	                  className="mt-1 block w-full rounded-md border border-gray-300 px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
386	                >
387	                  <option value="">All</option>
388	                  {categories.map((cat) => (
389	                    <option key={cat.id} value={cat.id}>
390	                      {cat.name}
391	                    </option>
392	                  ))}
393	                </select>
394	              </div>
395	
396	              {/* Min price */}
397	              <div>
398	                <label
399	                  htmlFor="filter-min-price"
400	                  className="block text-sm font-medium text-gray-700"
401	                >
402	                  Min Price ($)
403	                </label>
404	                <input
405	                  id="filter-min-price"
406	                  type="number"
407	                  min="0"
408	                  step="0.01"
409	                  value={minPrice}
410	                  onChange={(e) => {
411	                    setMinPrice(e.target.value);
412	                    setPage(1);
413	                  }}
414	                  className="mt-1 block w-full rounded-md border border-gray-300 px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
415	                />
416	              </div>
417	
418	              {/* Max price */}
419	              <div>
420	                <label
421	                  htmlFor="filter-max-price"
422	                  className="block text-sm font-medium text-gray-700"
423	                >
424	                  Max Price ($)
425	                </label>
426	                <input
427	                  id="filter-max-price"
428	                  type="number"
429	                  min="0"
430	                  step="0.01"
431	                  value={maxPrice}
432	                  onChange={(e) => {
433	                    setMaxPrice(e.target.value);
434	                    setPage(1);
435	                  }}
436	                  className="mt-1 block w-full rounded-md border border-gray-300 px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
437	                />
438	              </div>
439	
440	              {/* Min rating */}
441	              <div>
442	                <label
443	                  htmlFor="filter-min-rating"
