497	                    setPage(1);
498	                  }}
499	                  className="mt-1 block w-full rounded-md border border-gray-300 px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
500	                >
501	                  <option value="">Any Day</option>
502	                  {DAY_NAMES.map((day, idx) => (
503	                    <option key={idx} value={idx}>
504	                      {day}
505	                    </option>
506	                  ))}
507	                </select>
508	              </div>
509	            </div>
510	
511	            {/* Tags */}
512	            {tags.length > 0 && (
513	              <div className="mt-4">
514	                <p className="mb-2 text-sm font-medium text-gray-700">Tags</p>
515	                <div className="flex flex-wrap gap-2">
516	                  {tags.map((tag) => (
517	                    <label
518	                      key={tag.id}
519	                      className="flex items-center gap-1 text-sm text-gray-600"
520	                    >
521	                      <input
522	                        type="checkbox"
523	                        checked={selectedTagIds.includes(tag.id)}
524	                        onChange={() => toggleTag(tag.id)}
525	                        className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
526	                      />
527	                      {tag.name}
528	                    </label>
529	                  ))}
530	                </div>
531	              </div>
532	            )}
533	
534	            <div className="mt-4">
535	              <button
536	                onClick={clearFilters}
537	                className="text-sm text-blue-600 hover:text-blue-800"
538	              >
539	                Clear All Filters
540	              </button>
541	            </div>
542	          </div>
543	        )}
544	      </div>
545	
546	      {/* Error */}
547	      {error && (
548	        <div className="mb-4 rounded-md bg-red-50 p-3 text-sm text-red-700">
