556	          <h2 className="mb-4 text-lg font-semibold text-gray-900">
557	            Trending Services
558	          </h2>
559	          <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
560	            {trending.map((svc) => renderServiceCard(svc))}
561	          </div>
