                    <input id="filter-avail-start" type="time" value={availableStart} onChange={(e) => { setAvailableStart(e.target.value); setPage(1); }} className="mt-1 block w-full rounded-md border border-gray-300 px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500" />
                  </div>
                  <div>
                    <label htmlFor="filter-avail-end" className="block text-sm font-medium text-gray-700">Available Until (time)</label>
                    <input id="filter-avail-end" type="time" value={availableEnd} onChange={(e) => { setAvailableEnd(e.target.value); setPage(1); }} className="mt-1 block w-full rounded-md border border-gray-300 px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500" />
                  </div>
                </>
