1	import { Link } from "react-router-dom";
2	import { useQuery } from "@tanstack/react-query";
3	import { useCompareStore } from "../../stores/compare";
4	import { catalogApi } from "../../api/catalog";
5	
6	function formatPrice(cents: number): string {
7	  return `$${(cents / 100).toFixed(2)}`;
8	}
9	
10	function ComparePage() {
11	  const items = useCompareStore((s) => s.items);
12	  const remove = useCompareStore((s) => s.remove);
13	  const clear = useCompareStore((s) => s.clear);
14	
15	  // Fetch full detail (including availability) for each compared service
16	  const detailQueries = items.map((svc) =>
17	    // eslint-disable-next-line react-hooks/rules-of-hooks
18	    useQuery({
19	      queryKey: ["catalog-service-detail", svc.id],
20	      queryFn: () => catalogApi.getService(svc.id),
21	      enabled: Boolean(svc.id),
22	    }),
23	  );
24	
25	  if (items.length === 0) {
26	    return (
27	      <div>
28	        <h1 className="mb-6 text-2xl font-bold text-gray-900">Compare Services</h1>
29	        <div className="rounded-lg bg-white p-8 text-center shadow-sm">
30	          <p className="text-gray-500">Add services to compare from the catalog.</p>
31	          <Link to="/customer/catalog" className="mt-3 inline-block text-sm text-blue-600 hover:text-blue-800">Browse services</Link>
32	        </div>
33	      </div>
34	    );
35	  }
36	
37	  // Build availability summaries from detail data
38	  const DAY_NAMES = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
39	
40	  function availabilitySummary(idx: number): string {
41	    const detail = detailQueries[idx]?.data?.service;
42	    if (!detail || !detail.availability || detail.availability.length === 0)
43	      return "Not specified";
44	    const days = [...new Set(detail.availability.map((w) => w.day_of_week))].sort();
45	    return days.map((d) => {
46	      const windows = detail.availability.filter((w) => w.day_of_week === d);
47	      const times = windows.map((w) => `${w.start_time.slice(0,5)}-${w.end_time.slice(0,5)}`).join(", ");
48	      return `${DAY_NAMES[d]}: ${times}`;
49	    }).join("; ");
50	  }
51	
52	  return (
53	    <div>
54	      <div className="mb-6 flex items-center justify-between">
55	        <h1 className="text-2xl font-bold text-gray-900">Compare Services</h1>
56	        <div className="flex items-center gap-3">
57	          <Link to="/customer/catalog" className="text-sm text-blue-600 hover:text-blue-800">Back to Catalog</Link>
58	          <button onClick={clear} className="rounded-md bg-red-50 px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-100">Clear All</button>
59	        </div>
60	      </div>
61	
62	      <div className="overflow-x-auto rounded-lg bg-white shadow-sm">
63	        <table className="min-w-full divide-y divide-gray-200">
64	          <thead className="bg-gray-50">
65	            <tr>
66	              <th className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-gray-500">Field</th>
67	              {items.map((svc) => (
68	                <th key={svc.id} className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-gray-500">{svc.title}</th>
69	              ))}
70	            </tr>
71	          </thead>
72	          <tbody className="divide-y divide-gray-200">
73	            <tr>
74	              <td className="whitespace-nowrap px-6 py-3 text-sm font-medium text-gray-700">Provider</td>
75	              {items.map((svc) => (
76	                <td key={svc.id} className="whitespace-nowrap px-6 py-3 text-sm text-gray-900">{svc.provider.business_name}</td>
77	              ))}
78	            </tr>
79	            <tr>
80	              <td className="whitespace-nowrap px-6 py-3 text-sm font-medium text-gray-700">Price</td>
81	              {items.map((svc) => (
82	                <td key={svc.id} className="whitespace-nowrap px-6 py-3 text-sm font-bold text-gray-900">{formatPrice(svc.price_cents)}</td>
83	              ))}
84	            </tr>
85	            <tr>
86	              <td className="whitespace-nowrap px-6 py-3 text-sm font-medium text-gray-700">Rating</td>
87	              {items.map((svc) => (
88	                <td key={svc.id} className="whitespace-nowrap px-6 py-3 text-sm text-yellow-600">{parseFloat(svc.rating_avg).toFixed(2)} / 5.00</td>
89	              ))}
90	            </tr>
91	            <tr>
92	              <td className="whitespace-nowrap px-6 py-3 text-sm font-medium text-gray-700">Service Area</td>
93	              {items.map((svc, idx) => {
94	                const detail = detailQueries[idx]?.data?.service;
95	                return (
96	                  <td key={svc.id} className="whitespace-nowrap px-6 py-3 text-sm text-gray-900">
97	                    {detail ? "Local service area" : "Loading..."}
98	                  </td>
99	                );
100	              })}
101	            </tr>
102	            <tr>
103	              <td className="whitespace-nowrap px-6 py-3 text-sm font-medium text-gray-700">Category</td>
104	              {items.map((svc) => (
105	                <td key={svc.id} className="whitespace-nowrap px-6 py-3 text-sm text-gray-900">{svc.category?.name ?? "Uncategorized"}</td>
106	              ))}
107	            </tr>
108	            <tr>
109	              <td className="px-6 py-3 text-sm font-medium text-gray-700">Availability</td>
110	              {items.map((svc, idx) => (
111	                <td key={svc.id} className="px-6 py-3 text-sm text-gray-900" style={{ maxWidth: "200px" }}>
112	                  {detailQueries[idx]?.isLoading ? "Loading..." : availabilitySummary(idx)}
113	                </td>
114	              ))}
115	            </tr>
116	            <tr>
117	              <td className="px-6 py-3 text-sm font-medium text-gray-700">Tags</td>
118	              {items.map((svc) => (
119	                <td key={svc.id} className="px-6 py-3 text-sm text-gray-900">
120	                  {svc.tags.length > 0 ? svc.tags.map((t) => t.name).join(", ") : "None"}
121	                </td>
122	              ))}
123	            </tr>
124	            <tr>
125	              <td className="whitespace-nowrap px-6 py-3 text-sm font-medium text-gray-700">Popularity</td>
126	              {items.map((svc) => (
127	                <td key={svc.id} className="whitespace-nowrap px-6 py-3 text-sm text-gray-900">{svc.popularity_score}</td>
128	              ))}
129	            </tr>
130	            <tr>
131	              <td className="whitespace-nowrap px-6 py-3 text-sm font-medium text-gray-700">Actions</td>
132	              {items.map((svc) => (
133	                <td key={svc.id} className="whitespace-nowrap px-6 py-3">
134	                  <div className="flex items-center gap-2">
135	                    <Link to={`/customer/catalog/${svc.id}`} className="text-sm text-blue-600 hover:text-blue-800">View</Link>
136	                    <button onClick={() => remove(svc.id)} className="text-sm text-red-600 hover:text-red-800">Remove</button>
137	                  </div>
138	                </td>
139	              ))}
140	            </tr>
141	          </tbody>
142	        </table>
143	      </div>
144	    </div>
145	  );
146	}
147	
148	export default ComparePage;
