551	func (s *Service) scanServiceRows(rows *sql.Rows) ([]ServiceSummary, []string, error) {
552		services := make([]ServiceSummary, 0)
553		var serviceIDs []string
554	
555		for rows.Next() {
556			var svc ServiceSummary
557			var catID, catName *string
558			var provID, provBizName string
559	
560			if err := rows.Scan(
561				&svc.ID, &svc.Title, &svc.Description, &svc.PriceCents,
562				&svc.RatingAvg, &svc.PopularityScore, &svc.Status,
563				&svc.CreatedAt, &svc.UpdatedAt,
564				&catID, &catName,
565				&provID, &provBizName,
566			); err != nil {
567				return nil, nil, fmt.Errorf("catalog: scan service: %w", err)
568			}
569	
570			if catID != nil {
571				svc.Category = &CategoryRef{ID: *catID, Name: *catName}
572			}
573			svc.Provider = ProviderRef{ID: provID, BusinessName: provBizName}
574			svc.Tags = make([]TagRef, 0)
575	
576			services = append(services, svc)
577			serviceIDs = append(serviceIDs, svc.ID)
578		}
579		if err := rows.Err(); err != nil {
580			return nil, nil, fmt.Errorf("catalog: iterate services: %w", err)
