57	// extractUserID attempts to get the user ID from the auth_user context value.
58	func extractUserID(val interface{}) string {
59		// The auth_user value is an *auth.User. We use reflection-free approach:
60		// try to get ID field via the interface pattern.
61		type hasID interface {
62			GetID() string
63		}
64		if u, ok := val.(hasID); ok {
65			return u.GetID()
66		}
67		// Fallback: use type assertion on struct with ID field
68		// auth.User has exported ID string field — we can use a simple interface
69		type userLike struct {
70			ID string
71		}
72		// Use json round-trip as last resort, but first try direct struct field access
73		// via reflection-free duck typing.
74		// Since we know auth.User is a struct pointer with an ID field, marshal to JSON.
75		b, err := json.Marshal(val)
76		if err != nil {
77			return ""
78		}
79		var u userLike
80		if err := json.Unmarshal(b, &u); err != nil {
81			return ""
82		}
83		return u.ID
84	}
