103	func (s *Service) HandleCreateRule(c echo.Context) error {
104		ctx := c.Request().Context()
105		user := auth.UserFromContext(c)
106	
107		var req struct {
108			Name            string          `json:"name"`
109			Condition       json.RawMessage `json:"condition"`
110			Severity        string          `json:"severity"`
111			QuietHoursStart *string         `json:"quiet_hours_start"`
112			QuietHoursEnd   *string         `json:"quiet_hours_end"`
113			Enabled         *bool           `json:"enabled"`
114		}
115		if err := c.Bind(&req); err != nil {
116			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
117		}
118	
119		// Validate
120		fieldErrors := map[string][]string{}
121		if req.Name == "" {
122			fieldErrors["name"] = []string{"Name is required."}
123		}
124		if !validSeverities[req.Severity] {
125			fieldErrors["severity"] = []string{"Severity must be one of: low, medium, high, critical."}
126		}
127		if len(req.Condition) == 0 || string(req.Condition) == "null" {
128			fieldErrors["condition"] = []string{"Condition is required."}
129		}
130		if len(fieldErrors) > 0 {
131			return httpx.NewValidationError(fieldErrors)
132		}
133	
134		enabled := true
135		if req.Enabled != nil {
136			enabled = *req.Enabled
137		}
138	
139		var r AlertRule
