141			`INSERT INTO alert_rules (id, name, condition, severity, quiet_hours_start, quiet_hours_end, enabled, created_at, updated_at)
142			 VALUES ($1, $2, $3, $4, $5, $6, $7, NOW(), NOW())
143			 RETURNING id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled, created_at::text, updated_at::text`,
144			uuid.New().String(), req.Name, req.Condition, req.Severity, req.QuietHoursStart, req.QuietHoursEnd, enabled,
145		).Scan(&r.ID, &r.Name, &r.Condition, &r.Severity, &r.QuietHoursStart, &r.QuietHoursEnd, &r.Enabled, &r.CreatedAt, &r.UpdatedAt)
