package crypto

import (
    "crypto/aes"
    "crypto/cipher"
    "crypto/rand"
    "encoding/hex"
    "errors"
    "fmt"
    "io"
    "os"
)

// Key reads the ENCRYPTION_KEY env var (64 hex chars = 32 bytes = AES-256).
func Key() ([]byte, error) {
    hexKey := os.Getenv("ENCRYPTION_KEY")
    if hexKey == "" {
        return nil, errors.New("ENCRYPTION_KEY not set")
    }
    return hex.DecodeString(hexKey)
}

// Encrypt encrypts plaintext using AES-256-GCM and returns hex-encoded ciphertext.
func Encrypt(key []byte, plaintext string) (string, error) {
    block, err := aes.NewCipher(key)
    if err != nil { return "", fmt.Errorf("crypto: new cipher: %w", err) }
    gcm, err := cipher.NewGCM(block)
    if err != nil { return "", fmt.Errorf("crypto: new gcm: %w", err) }
    nonce := make([]byte, gcm.NonceSize())
    if _, err := io.ReadFull(rand.Reader, nonce); err != nil { return "", err }
    ciphertext := gcm.Seal(nonce, nonce, []byte(plaintext), nil)
    return hex.EncodeToString(ciphertext), nil
}

// Decrypt decrypts hex-encoded AES-256-GCM ciphertext and returns plaintext.
func Decrypt(key []byte, hexCiphertext string) (string, error) {
    ciphertext, err := hex.DecodeString(hexCiphertext)
    if err != nil { return "", fmt.Errorf("crypto: decode hex: %w", err) }
    block, err := aes.NewCipher(key)
    if err != nil { return "", fmt.Errorf("crypto: new cipher: %w", err) }
    gcm, err := cipher.NewGCM(block)
    if err != nil { return "", fmt.Errorf("crypto: new gcm: %w", err) }
    nonceSize := gcm.NonceSize()
    if len(ciphertext) < nonceSize { return "", errors.New("crypto: ciphertext too short") }
    nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
    plaintext, err := gcm.Open(nil, nonce, ct, nil)
    if err != nil { return "", fmt.Errorf("crypto: decrypt: %w", err) }
    return string(plaintext), nil
}
