	// Now advance to "today" — this should trigger rotation and seal yesterday's file
	today := time.Date(2025, 6, 15, 8, 0, 0, 0, time.UTC)
	sink.NowFn = func() time.Time { return today }

	err = sink.Write(map[string]interface{}{
