	perm := info.Mode().Perm()
	if perm&0222 != 0 {
		t.Fatalf("yesterday file should be read-only after rotation, got permissions %o", perm)
	}

	// Verify today's file is still writable
	info2, err := os.Stat(todayFile)
	if err != nil {
		t.Fatalf("stat today file: %v", err)
	}
	perm2 := info2.Mode().Perm()
	if perm2&0200 == 0 {
		t.Fatalf("today file should still be writable, got permissions %o", perm2)
	}

	// Verify both files contain their events
	data1, _ := os.ReadFile(yesterdayFile)
	if !strings.Contains(string(data1), "test_event") {
		t.Fatal("yesterday file should contain test_event")
	}
	data2, _ := os.ReadFile(todayFile)
	if !strings.Contains(string(data2), "today_event") {
		t.Fatal("today file should contain today_event")
	}
}

